// Knot weight loader.
//
// Reference: GGUF format / `token_embd_weight` conventions —
// github.com/ggerganov/ggml (GGUF spec, Gerganov 2024) and
// github.com/ggerganov/llama.cpp (k-quant blocks).
//
// Two backends behind one trait:
//   - MmapBackend: local .knot file, zero-copy, demand-paged by the OS.
//   - HttpBackend: R2-backed URL, HTTP Range requests with an LRU layer cache
//     and a worker thread pool for prefetch overlap.
//
// `OwnedBytes` is the unified return type. For Mmap it's a refcounted handle
// that borrows from the underlying mmap (no copy). For HTTP it's an Arc<Vec<u8>>
// whose buffer was filled by a Range fetch and stored in the LRU.
//
// `KnotWeights` parses the knot header once at open time:
//   bytes 0..4   : "KNOT" magic
//   bytes 4..6   : version (u16 LE)
//   bytes 6..10  : metadata length (u32 LE)
//   bytes 10..   : metadata JSON (length above), padded to 4-byte alignment
//   then         : codec marker byte
//   then         : tensor payload
//
// Metadata schema:
//   {
//     "name": "qwen-coder-7b",
//     "codec": "bitwise-fp64",
//     "topology": "attention-mesh",
//     "components": {                         // optional: pipeline parts carried
//       "included": ["transformer", "vae"],
//       "skipped": ["tokenizer", "scheduler"],
//       "policy": "flux-with-vae-text-encoders"
//     },
//     "config": {                              // optional: model dims
//       "hidden_dim": 3584, "num_layers": 28,
//       "num_heads": 28,    "num_kv_heads": 4,
//       "head_dim": 128,    "intermediate_size": 18944,
//       "vocab_size": 152064,
//       "rms_norm_eps": 1.0e-5,
//       "rope_theta": 1000000.0
//     },
//     "tensors": {
//       "blk_0_attn_q_weight.bin": {
//         "offset": 0,
//         "length": 25690112,
//         "type": "Q4_K",
//         "shape": [3584, 3584]
//       },
//       ...
//     }
//   }

use bitwise::kn0t_format;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::ops::Deref;
use std::sync::Arc;

// Native-only imports. The mmap + HTTP-Range backends and their worker thread
// pool are unavailable on wasm32; the wasm path delegates fetch to the JS host
// and uses only the cross-target portions of this module.
#[cfg(not(target_arch = "wasm32"))]
use memmap2::Mmap;
#[cfg(not(target_arch = "wasm32"))]
use parking_lot::Mutex;
#[cfg(not(target_arch = "wasm32"))]
use std::fs::File;
#[cfg(not(target_arch = "wasm32"))]
use std::io::{Read, Seek, SeekFrom};
#[cfg(not(target_arch = "wasm32"))]
use std::sync::Condvar;
#[cfg(not(target_arch = "wasm32"))]
use std::sync::Mutex as StdMutex;
#[cfg(not(target_arch = "wasm32"))]
use std::thread;
#[cfg(not(target_arch = "wasm32"))]
use std::time::Duration;

#[derive(Deserialize, Debug, Clone, Copy, PartialEq, Eq)]
pub enum KnotCodec {
    /// 16-bit floats (2 bytes / element). Marker byte `0x10`.
    #[serde(rename = "fp16")]
    Fp16,
    /// 32-bit floats (4 bytes / element). Marker byte `0x20`.
    #[serde(rename = "fp32")]
    Fp32,
}

impl KnotCodec {
    /// Number of payload bytes per scalar element under this codec.
    #[inline]
    pub fn bytes_per_element(self) -> usize {
        match self {
            KnotCodec::Fp16 => 2,
            KnotCodec::Fp32 => 4,
        }
    }
}

/// Resolve the payload codec from a `.knot` metadata JSON blob.
///
/// Reads the top-level `"codec"` string (e.g. `"fp16"`, `"fp32"`) — defaults
/// to `Fp32` when the field is absent so legacy knots written before the
/// codec field was added continue to load correctly.
pub fn parse_knot_codec(meta: &serde_json::Value) -> KnotCodec {
    meta.get("codec")
        .and_then(|v| v.as_str())
        .and_then(|s| match s {
            "fp16" => Some(KnotCodec::Fp16),
            "fp32" => Some(KnotCodec::Fp32),
            _ => None,
        })
        .unwrap_or(KnotCodec::Fp32)
}

/// Read the raw `.knot` (v1) file and extract its top-level metadata JSON
/// value — including `tensors` inline, which is exactly why this is `.knot`-
/// only: `.kn0t` (v3) has no equivalent single JSON blob to return (its TOC
/// is binary, by design). Both real callers (`pneuma-tts-smoke.rs`,
/// `rknot/dense_reader.rs`) legitimately want dense `.knot` files
/// specifically, so this intentionally does not dispatch to `.kn0t` — use
/// [`parse_knot_header_prefix`] for a format-agnostic read instead.
#[cfg(not(target_arch = "wasm32"))]
pub fn read_knot_metadata(path: &str) -> Result<serde_json::Value, String> {
    let mut f = File::open(path).map_err(|e| format!("read {}: {}", path, e))?;
    let mut magic = [0u8; 4];
    f.read_exact(&mut magic).map_err(|e| e.to_string())?;
    if &magic == kn0t_format::KN0T_MAGIC {
        return Err(format!(
            "{} is a .kn0t (v3) file — read_knot_metadata only supports .knot (v1); \
             use parse_knot_header_prefix for a format-agnostic read",
            path
        ));
    }
    if &magic != b"KNOT" {
        return Err(format!("{} is not a KNOT file (bad magic)", path));
    }
    // Skip version (2 bytes)
    let mut skip = [0u8; 2];
    f.read_exact(&mut skip).map_err(|e| e.to_string())?;
    // Read meta_len (4 bytes)
    let mut meta_len_bytes = [0u8; 4];
    f.read_exact(&mut meta_len_bytes)
        .map_err(|e| e.to_string())?;
    let meta_len = u32::from_le_bytes(meta_len_bytes) as usize;

    let mut meta_bytes = vec![0u8; meta_len];
    f.read_exact(&mut meta_bytes).map_err(|e| e.to_string())?;

    let meta_str = std::str::from_utf8(&meta_bytes)
        .map_err(|e| format!("metadata utf8 in {}: {}", path, e))?;
    serde_json::from_str(meta_str).map_err(|e| format!("metadata json in {}: {}", path, e))
}

#[derive(Serialize, Deserialize, Debug, Clone)]
pub struct TensorInfo {
    /// Byte offset into the knot payload. **MUST be u64**, not usize —
    /// on wasm32 `usize = u32` (max ~4.29 GB) but a 17 GB gemma4 knot
    /// has tensor offsets up to ~17e9. Pre-fix every tensor at offset
    /// >4 GB silently failed to deserialize and the parser lost ~669/833
    /// > entries — the worker only saw tensors from the first ~4 GB of
    /// > knot, panicked on missing layer-N tensors at boot.
    pub offset: u64,
    /// Per-tensor byte length. Bounded by hidden_dim * vocab_size for
    /// embedding (worst case ≈ 1 GB on gemma4-31B-q4k) so u32 is OK,
    /// but use u64 for symmetry with `offset`.
    pub length: u64,
    #[serde(rename = "type")]
    pub tensor_type: String,
    /// Optional row-major tensor shape from the source framework. Legacy KNOTs
    /// omit this; FLUX runtime paths require it because text encoders, DiT
    /// blocks, and VAE kernels cannot infer safe matrix dimensions from byte
    /// lengths alone.
    #[serde(default)]
    pub shape: Option<Vec<usize>>,
}

#[cfg(not(target_arch = "wasm32"))]
#[derive(Debug, Clone)]
pub struct FetchedKnotTensor {
    pub name: String,
    pub info: TensorInfo,
    pub bytes: Vec<u8>,
}

#[cfg(not(target_arch = "wasm32"))]
const DEFAULT_TENSOR_RANGE_CHUNK_BYTES: usize = 32 * 1024 * 1024;

/// Optional top-level dense KNOT component envelope.
///
/// FLUX uses this to make non-transformer coverage explicit: `encode-knot.py`
/// can carry VAE, CLIP, and T5 tensors while still recording skipped non-weight
/// diffusers directories such as tokenizers and scheduler config. This stays
/// outside [`KnotConfig`] so older architecture readers keep ignoring it.
#[derive(Serialize, Deserialize, Debug, Clone, PartialEq, Eq)]
pub struct KnotComponents {
    #[serde(default)]
    pub included: Vec<String>,
    #[serde(default)]
    pub skipped: Vec<String>,
    #[serde(default)]
    pub policy: Option<String>,
}

impl KnotComponents {
    pub fn includes(&self, component: &str) -> bool {
        self.included.iter().any(|name| name == component)
    }

    pub fn skips(&self, component: &str) -> bool {
        self.skipped.iter().any(|name| name == component)
    }
}

/// Model dimensions carried inside the knot metadata. Optional for backwards
/// compatibility with legacy 1B knots that pre-date the config block; in that
/// case the loader returns None and the model falls back to TinyLlama defaults.
///
/// Architecture-specific fields are all `Option<_>` so a Qwen2 / LLaMA knot
/// (which omits them) deserializes cleanly. The model layer reads them and
/// branches on `Some(_)` to enable Gemma3/Gemma4 paths (sliding-window
/// attention dispatch, partial RoPE, post-attn / post-FFW norms, final-logit
/// softcap, etc.). See `model_gemma4.rs` for the consumer.
#[derive(Deserialize, Debug, Clone)]
pub struct KnotConfig {
    pub hidden_dim: usize,
    pub num_layers: usize,
    pub num_heads: usize,
    pub num_kv_heads: usize,
    pub head_dim: usize,
    pub intermediate_size: usize,
    pub vocab_size: usize,
    #[serde(default = "default_rms_norm_eps")]
    pub rms_norm_eps: f32,
    #[serde(default = "default_rope_theta")]
    pub rope_theta: f32,
    /// Architecture discriminator from GGUF `general.architecture`. Defaults
    /// to "qwen2" so legacy knots without this field continue to load through
    /// the original Qwen2 forward path. Known values: "qwen2", "gemma3",
    /// "gemma4". Note that Gemma 4 GGUFs sometimes self-identify as "gemma3"
    /// — the knot encoder is responsible for normalizing.
    #[serde(default = "default_arch")]
    pub arch: String,
    // ─── Gemma3 / Gemma4 architecture fields ───────────────────────────────
    /// Tanh logit softcap applied at the end of `lm_head` (Gemma4: 30.0).
    /// `logits[i] = tanh(logits[i] / cap) * cap`. None ⇒ skip the softcap.
    #[serde(default)]
    pub final_logit_softcap: Option<f32>,
    /// Q-side pre-attention scalar. Attention scores are scaled by
    /// `1 / sqrt(query_pre_attn_scalar)` instead of the usual
    /// `1 / sqrt(head_dim)`. Gemma4-31B = 168.0; Gemma4-E4B = 256.0.
    /// None ⇒ fall back to `1/sqrt(head_dim)` (LLaMA / Qwen2 default).
    #[serde(default)]
    pub query_pre_attn_scalar: Option<f32>,
    /// Sliding-window pattern: every Nth layer is a global-attention layer;
    /// the rest use sliding (windowed) attention. Gemma3 = 6 (so layers 5,
    /// 11, 17, 23, 29, 35, 41, 47, 53, 59 are global on a 60-layer model).
    /// None ⇒ all layers global (LLaMA / Qwen2 default).
    #[serde(default)]
    pub sliding_window_pattern: Option<usize>,
    /// Sliding window size for non-global layers. Gemma4-31B = 1024.
    #[serde(default)]
    pub sliding_window: Option<usize>,
    /// Head dim used on global-attention layers. Gemma4-31B = 512 (vs the
    /// non-global default of `head_dim` = 256). None ⇒ use `head_dim`.
    #[serde(default)]
    pub global_head_dim: Option<usize>,
    /// KV head count on global-attention layers. Gemma4-31B = 4 (vs the
    /// non-global default of `num_kv_heads` = 16). None ⇒ use `num_kv_heads`.
    #[serde(default)]
    pub global_num_kv_heads: Option<usize>,
    /// RoPE base frequency for sliding-window (local) layers. Gemma4 = 10000.
    /// Global-attention layers continue to use `rope_theta`. None ⇒ same as
    /// `rope_theta` everywhere.
    #[serde(default)]
    pub rope_local_base_freq: Option<f32>,
    /// Linear RoPE scaling factor applied on global-attention layers.
    /// Gemma4 = 8.0. None ⇒ no scaling.
    #[serde(default)]
    pub rope_scaling_factor: Option<f32>,
    /// Fraction of head_dim that participates in RoPE (Gemma4 partial-RoPE).
    /// Gemma4 = 0.25 (rotate first 25% of each head, copy through the rest).
    /// None ⇒ rotate the full head_dim (LLaMA / Qwen2 default).
    #[serde(default)]
    pub rope_partial_factor: Option<f32>,

    // ─── SSM (Mamba-1 / Mamba-2 / FalconMamba) architecture fields ───────────
    /// SSM state dimension. Mamba-2.8b = 16, FalconMamba-7b = 16 (both are the
    /// Mamba-1 S6 architecture; FalconMamba is NOT Mamba-2/SSD, it only adds
    /// weightless dt/B/C RMSNorms). None ⇒ not an SSM model.
    #[serde(default)]
    pub d_state: Option<usize>,
    /// Causal conv1d kernel size. Mamba default = 4.
    #[serde(default)]
    pub d_conv: Option<usize>,
    /// SSM expansion factor: d_inner = ssm_expand * hidden_dim. Default = 2.
    #[serde(default)]
    pub ssm_expand: Option<usize>,
    /// dt projection rank for Mamba-1 S6 kernel (ceil(hidden_dim/16) typically).
    /// None on a Mamba-1 knot (mamba / falcon-mamba) that omitted time_step_rank
    /// is reconstructed as ceil(hidden/16) in MambaPipeline::from_knot.
    #[serde(default)]
    pub dt_rank: Option<usize>,
    /// Mamba-2 SSD: number of B/C groups (n_groups). B/C are shared across
    /// heads_per_group = num_heads / ssm_n_groups. codestral = 8.
    #[serde(default)]
    pub ssm_n_groups: Option<usize>,
    /// Mamba-2 SSD chunk size (parallel-prefill duality). codestral = 256.
    #[serde(default)]
    pub ssm_chunk_size: Option<usize>,

    // ─── RWKV-7 architecture fields ──────────────────────────────────────────
    /// Number of WKV attention heads. RWKV7-2.9B = 32.
    #[serde(default)]
    pub rwkv_n_heads: Option<usize>,
    /// Low rank for dynamic time decay w = exp(-sigmoid(w0 + tanh(xw@w1)@w2)).
    #[serde(default)]
    pub rwkv_low_rank_w: Option<usize>,
    /// Low rank for dynamic attention a = sigmoid(a0 + (xa@a1)@a2).
    #[serde(default)]
    pub rwkv_low_rank_a: Option<usize>,
    /// Low rank for value versioning gate.
    #[serde(default)]
    pub rwkv_low_rank_v: Option<usize>,
    /// Inner dim for two-stage gate g = sigmoid(xg@g1)@g2.
    #[serde(default)]
    pub rwkv_gate_inner: Option<usize>,

    // ─── Hybrid SSM+Transformer fields (Jamba, Falcon-H1) ────────────────────
    /// Spacing between attention layers. Every N-th layer (0-indexed, (l+1)%N==0)
    /// is a Transformer attention block; the rest are Mamba-2 SSM blocks.
    /// Jamba default = 8, Falcon-H1 default = 2. None ⇒ arch default.
    #[serde(default)]
    pub hybrid_attn_layer_period: Option<usize>,
    /// KV-cache depth for attention layers. Governs max sequence length for
    /// autoregressive decode. None ⇒ 2048.
    #[serde(default)]
    pub max_seq_len: Option<usize>,
    /// Number of MoE experts per sparse FFN layer (Jamba = 16). None ⇒ the
    /// model has no MoE FFN layers, OR the count is derived at load time by
    /// counting `blk_N_expert_*` tensors present in the knot header (the Jamba
    /// encoder currently omits this field — see `encode-ssm-models.py`).
    #[serde(default)]
    pub num_experts: Option<usize>,
    /// Top-k experts activated per token in MoE layers (Jamba = 2). None ⇒ the
    /// arch default (2 for Jamba), matching HF `num_experts_per_tok`.
    #[serde(default)]
    pub num_experts_per_tok: Option<usize>,
}

fn default_rms_norm_eps() -> f32 {
    1.0e-5
}
fn default_rope_theta() -> f32 {
    10000.0
}
fn default_arch() -> String {
    "qwen2".to_string()
}

// ─────────────────────────────────────────────────────────────────────────
// OwnedBytes: unified weight handle
// ─────────────────────────────────────────────────────────────────────────

/// Bytes that the model layer can read for the duration of a matmul.
/// For Mmap, it's a zero-copy handle into the file mapping. For HTTP (and the
/// wasm/host-fetched path), it's a refcounted Vec<u8>.
#[derive(Clone)]
pub enum OwnedBytes {
    #[cfg(not(target_arch = "wasm32"))]
    Mmap {
        mmap: Arc<Mmap>,
        start: usize,
        end: usize,
    },
    Owned(Arc<Vec<u8>>),
}

impl Deref for OwnedBytes {
    type Target = [u8];
    fn deref(&self) -> &[u8] {
        match self {
            #[cfg(not(target_arch = "wasm32"))]
            OwnedBytes::Mmap { mmap, start, end } => &mmap[*start..*end],
            OwnedBytes::Owned(buf) => buf.as_slice(),
        }
    }
}

impl AsRef<[u8]> for OwnedBytes {
    fn as_ref(&self) -> &[u8] {
        self
    }
}

// ─────────────────────────────────────────────────────────────────────────
// WeightBackend trait
// ─────────────────────────────────────────────────────────────────────────

pub trait WeightBackend: Send + Sync {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String>;
    fn has_tensor(&self, name: &str) -> bool;
    /// Hint that tensors named in `names` will be needed soon. Implementations
    /// may begin async prefetch but must not block. Default impl is a no-op.
    fn prefetch(&self, _names: &[String]) {}
    /// For downcasting Arc<dyn WeightBackend> to a concrete implementation.
    fn as_any(&self) -> &dyn std::any::Any;
    /// Optional: return the original `TensorInfo` (offset / length / qtype)
    /// for a named tensor so callers can interpret raw `fetch_tensor` bytes
    /// against the source quant layout (Q4_K / Q5_K / Q6_K / fp16 / fp32).
    /// Default `None` means "this backend does not expose source metadata."
    /// `MmapBackend` and `HttpBackend` override to return their cached
    /// `metadata.get(name).cloned()`. Used by the paris-probe-rknot
    /// `--fidelity-check` codepath to dequantize the dense Q4_K_M / Q6_K
    /// source bytes back to fp32 before comparing them element-wise to the
    /// rknot decoded tensor.
    fn tensor_info(&self, _name: &str) -> Option<TensorInfo> {
        None
    }
}

// ─────────────────────────────────────────────────────────────────────────
// WasmHostBackendInner (wasm32-only — host-populated tensor map)
// ─────────────────────────────────────────────────────────────────────────
//
// On wasm32 the JS host is the prefetch orchestrator: it speaks Promises (the
// only way to do `fetch()` on Workers), it owns the LRU, and it sequences
// service-binding calls. This Rust-side backend is a passive cache the host
// fills in before each call into the model.
//
// Shared host-side prefetch/LRU logic lives in the
// `@a0n/distributed-inference-host` TS package (see `docs/wasm-host.md`),
// imported by every Worker — i.e., the policy is written once across all
// Worker deployments and the Rust crate doesn't reinvent it.
//
// This is the *inner* type. The public JS-facing wrapper lives in
// `wasm_bindings::WasmHostBackend`, which owns an `Arc<WasmHostBackendInner>`
// and re-exposes the same surface with `#[wasm_bindgen]` annotations. Keeping
// the inner type free of wasm-bindgen lets it implement `WeightBackend`
// (which uses `&dyn`/`Arc<dyn>` — not allowed across the wasm-bindgen ABI).
//
// Host contract:
//   1. Host parses the knot header (use `parse_tensors` / `parse_config` if it
//      wants to do that inside WASM, or do it in JS).
//   2. Host instantiates `WasmHostBackend::new(metadata)`.
//   3. Before invoking `pipeline.forward_one(...)`, the host awaits all the
//      tensor fetches for that step's layer chunk and calls `set_tensor` for
//      each one.
//   4. Inside the model, `fetch_tensor(name)` returns the cached bytes; if a
//      tensor wasn't pre-loaded the call panics — by design, surfaces a host
//      orchestration bug.
//   5. After the layer chunk is consumed, the host calls `evict_layer(names)`
//      to free memory. (LRU policy lives in the host shim, not here.)

#[cfg(target_arch = "wasm32")]
pub struct WasmHostBackendInner {
    metadata: HashMap<String, TensorInfo>,
    /// Bytes the host has loaded. `std::sync::Mutex` because `WeightBackend`
    /// requires `Sync`; on wasm32-unknown-unknown there is no real contention.
    cache: std::sync::Mutex<HashMap<String, Arc<Vec<u8>>>>,
}

#[cfg(target_arch = "wasm32")]
impl WasmHostBackendInner {
    pub fn new(metadata: HashMap<String, TensorInfo>) -> Self {
        Self {
            metadata,
            cache: std::sync::Mutex::new(HashMap::new()),
        }
    }

    /// Host-side setter. Called from JS once a service-binding fetch resolves.
    pub fn set_tensor(&self, name: &str, bytes: Vec<u8>) {
        self.cache
            .lock()
            .unwrap()
            .insert(name.to_string(), Arc::new(bytes));
    }

    /// Host-side eviction. Called by the JS shim after a layer is consumed.
    pub fn evict(&self, names: &[String]) {
        let mut guard = self.cache.lock().unwrap();
        for n in names {
            guard.remove(n);
        }
    }

    /// Return the tensor metadata so the host shim can compute byte ranges.
    pub fn tensor_info(&self, name: &str) -> Option<&TensorInfo> {
        self.metadata.get(name)
    }

    /// Clone the metadata map so the wasm-bindgen wrapper can hand it to
    /// `KnotWeights::from_parts` without losing the inner Arc's lone owner.
    pub fn metadata_clone(&self) -> HashMap<String, TensorInfo> {
        self.metadata.clone()
    }
}

#[cfg(target_arch = "wasm32")]
impl WeightBackend for WasmHostBackendInner {
    fn fetch_tensor(&self, name: &str) -> Result<OwnedBytes, String> {
        // Take the Arc out of the cache while holding the lock, then DROP
        // the guard before doing anything else. The previous shape held
        // the guard across the `match` and called `panic!` from the `None`
        // arm — on wasm32 with `panic = "abort"` (the default for this
        // crate), the panic compiles to `unreachable`, the MutexGuard's
        // Drop is SKIPPED, and the cache's std::sync::Mutex stays "locked"
        // forever. The very next `set_tensor` (which also locks the cache)
        // then panics inside `std::sys::sync::mutex::no_threads` with
        // `cannot recursively acquire mutex`, which on the JS side surfaces
        // as the wasm-bindgen "recursive use of an object detected" string
        // (the same panic also poisons the WasmRefCell borrow flag for the
        // pipeline because `forward_range_attn_chunk`'s borrow_mut epilogue
        // is also skipped). Result: the entire isolate is wedged after one
        // missing-tensor panic.
        //
        // Repro:
        //   apps/distributed-inference-worker/test-harness/probe-borrow-flag.mjs
        //
        // Investigation: docs/pneuma/wasm-forward-bug-investigation.md.
        //
        // FIX: Return Result<()> instead of panicking to ensure proper Drop
        // behavior and isolate stability.
        let cached = {
            let guard = self.cache.lock().unwrap();
            guard.get(name).map(Arc::clone)
        };
        match cached {
            Some(arc) => {
                // Truncation guard. A recycled isolate can be re-pinned from an
                // interrupted R2 range fetch, leaving a SHORT weight buffer. A
                // short buffer makes a downstream kernel (e.g. mat_vec_q4k, which
                // asserts `w.len() >= n*bpr*144`) panic; on wasm32 `panic=abort`
                // that traps `unreachable`, SKIPS the `&mut self` borrow-flag
                // epilogue, and wedges the whole isolate ("recursive use of an
                // object") for every later request — the persistent outage. A
                // clean Err here (callers propagate it with `?`) returns the
                // pipeline method normally, keeps the isolate healthy, and lets
                // the host re-pin + the caller retry.
                // See docs/pneuma/wasm-forward-bug-investigation.md.
                if let Some(info) = self.metadata.get(name) {
                    if (arc.len() as u64) < info.length {
                        return Err(format!(
                            "WasmHostBackendInner: tensor '{}' truncated ({} bytes < expected {}); \
                             refusing the forward to avoid a wasm-wedging short-buffer panic",
                            name,
                            arc.len(),
                            info.length
                        ));
                    }
                }
                Ok(OwnedBytes::Owned(arc))
            }
            None => Err(format!(
                "WasmHostBackendInner: tensor '{}' not pre-loaded; host shim must \
                 set_tensor before forward_one consumes the layer chunk",
                name
            )),
        }
    }

    fn has_tensor(&self, name: &str) -> bool {
        self.metadata.contains_key(name)
    }

    /// Prefetch is a no-op: the host orchestrates async fetches and calls
    /// `set_tensor` synchronously before re-entering WASM.
    fn prefetch(&self, _names: &[String]) {}
    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
    /// Expose the host-supplied per-tensor metadata (offset / length / quant
    /// type) to in-WASM consumers that read it through the trait object. Without
    /// this override the default returned `None`, so the RWKV-7 Q8-resident path
    /// (which reads `tensor_info(name).tensor_type` to pick the dequant kernel)
    /// would treat every Q8_0 / F16 weight as F32 and decode garbage. The
    /// JS-facing `WasmHostBackend::tensor_info` wrapper uses the inherent method;
    /// this is the Rust-side `&dyn WeightBackend` path.
    fn tensor_info(&self, name: &str) -> Option<TensorInfo> {
        self.metadata.get(name).cloned()
    }
}

// ─────────────────────────────────────────────────────────────────────────
